-- Clean up test players
DELETE FROM players WHERE deviceId LIKE 'e2e-test-%' OR deviceId LIKE 'curl-test-%';

-- Clean up test puzzle attempts  
DELETE FROM puzzle_attempts WHERE trainingSetId LIKE 'e2e-set-%' OR trainingSetId LIKE 'test-set-%';

-- Clean up test cycle history
DELETE FROM cycle_history WHERE deviceId LIKE 'e2e-test-%';

-- Verify clean state
SELECT COUNT(*) as playerCount FROM players WHERE totalPuzzles > 0;

